function data = mdp_PCA(data, varargin)%MDP_PCA  - MVIEW dataproc that maps movement trajectories onto their 1st principal component%% appends *_PC1 signals to DATA for each movement trajectory specified in varargin%% usage example: %% compute PC1 for HEAD trajectory% mview(...,'DPROC',{{'mdp_PCA',{'HEAD'}}}, ...)%% use directly with e.g. mdp_PCA(d,'TR','TT','JAW','HEAD',[]) % mkt 02/17varargin(end) = [];			% last arg is {pal,phar,labs}for ti = 1 : length(varargin),	tName = varargin{ti};	if isempty(tName), error('no trajectory name specified'); end;	k = find(strcmp(tName,{data.NAME}));	if isempty(k), error('%s not found', tName); end;	s = data(k).SIGNAL;	if size(s,2) < 3, error('%s is monodimensional', tName); end;	[pcs,pcd,pcv] = pca(s(:,1:3));	fprintf('%s PCA:  %.1f %.1f %.1f\n', tName, 100*pcv./sum(pcv));	n = length(data) + 1;	data(n).NAME = sprintf('%sPC1', tName);	data(n).SRATE = data(k).SRATE;	data(n).NCOMPS = 1;	data(n).SIGNAL = pcd(:,1);	minS = min(data(n).SIGNAL);	maxS = max(data(n).SIGNAL);	spread = maxS - minS;	data(n).SPREAD = [minS-spread*.1 maxS+spread*.1];	%padend